const fs = require('fs');
const path = require('path');

app.get('/read', (req, res) => {
  const requestedFile = req.query.file;
  const baseDir = path.resolve(__dirname, 'safe_files'); // Define a secure base directory for files

  // 1. Validate input: Ensure filename is not empty, doesn't contain '..' for traversal, and isn't an absolute path
  if (!requestedFile || requestedFile.includes('..') || path.isAbsolute(requestedFile)) {
    return res.status(400).send('Invalid file path.');
  }

  // 2. Construct the full path using path.join() to safely combine baseDir and requestedFile
  const filePath = path.join(baseDir, requestedFile);

  // 3. Crucially, verify that the resolved filePath is still strictly within the baseDir.
  // This prevents attackers from using symlinks or other tricks to escape the intended directory.
  if (!filePath.startsWith(baseDir + path.sep) && filePath !== baseDir) {
    return res.status(403).send('Access denied: Path outside allowed directory.');
  }

  fs.readFile(filePath, 'utf8', (err, data) => {
    if (err) {
      if (err.code === 'ENOENT') { return res.status(404).send('File not found.'); }
      console.error('File read error:', err.message); // Log full error for debugging
      return res.status(500).send('Error reading file.');
    }
    res.send(data);
  });
});

